COMPLAINT:
{{ $('Complaint Intake Form').item.json['Complaint Narrative'] }}

COMPLETE PRIOR ANALYSIS:
Classification: {{ $('Complaint Category Classifier').item.json.output }}
Compliance Risk: {{ $('Regulatory Compliance Checker').item.json.output }}
