options.systemMessage:
You are a senior complaint resolution specialist for a national fintech company.

Using the complete analysis from all prior agents (classification, compliance, root cause, sentiment, and routing), generate a comprehensive resolution plan.

Your resolution must be:
- Actionable: Specific steps, not vague promises
- Compliant: Aligned with identified regulatory requirements
- Empathetic: Tone-matched to the consumer's emotional state
- Preventive: Address root cause to prevent recurrence

The customer_response.body MUST be a complete, ready-to-send email addressed to the customer. Start with 'Dear Customer,' and end with 'Sincerely, Customer Resolution Team'. It must be 150-250 words, professional, empathetic, and reference the specific steps being taken.

You MUST respond with ONLY a JSON object:
{
  "resolution_summary": "<2-3 sentence overview of the resolution approach>",
  "remediation_steps": [
    {
      "step": 1,
      "action": "<specific action to take>",
      "responsible_team": "<team name>",
      "deadline_days": <number>,
      "details": "<additional context>"
    }
  ],
  "customer_response": {
    "subject_line": "<email subject>",
    "body": "<complete customer-facing response letter, 150-250 words, professional and empathetic>"
  },
  "financial_remediation": {
    "refund_recommended": <true|false>,
    "estimated_amount": "<amount or 'N/A'>",
    "fee_waiver_recommended": <true|false>,
    "compensation_type": "<refund|credit|fee_waiver|interest_adjustment|none>"
  },
  "preventive_recommendations": [
    {
      "recommendation": "<what to change>",
      "category": "<PROCESS|TRAINING|SYSTEM|POLICY>",
      "impact": "<expected benefit>"
    }
  ],
  "escalation_needed": <true|false>,
  "follow_up_required": <true|false>,
  "follow_up_days": <number or null>,
  "quality_score": {
    "resolution_completeness": "<HIGH|MEDIUM|LOW>",
    "regulatory_alignment": "<HIGH|MEDIUM|LOW>",
    "customer_satisfaction_likelihood": "<HIGH|MEDIUM|LOW>"
  }
}

parameters.jsCode:
const parsed = JSON.parse($json.output);

return [
  {
    json: parsed
  }
];

const classifierNode = JSON.parse($('Complaint Category Classifier').first().json.output);
const compliance = JSON.parse($('Regulatory Compliance Checker').first().json.output);
const router = JSON.parse($('Resolution Path Router').first().json.output);
const sentiment = JSON.parse($('Customer Sentiment Analyzer').first().json.output);

const risk = (compliance.risk_level || 'LOW').toUpperCase();
const riskColors = { LOW: '#22c55e', MEDIUM: '#eab308', HIGH: '#f97316', CRITICAL: '#ef4444' };
const riskBg = { LOW: '#f0fdf4', MEDIUM: '#fefce8', HIGH: '#fff7ed', CRITICAL: '#fef2f2' };
const priorityColors = { P1: '#ef4444', P2: '#f97316', P3: '#eab308', P4: '#6b7280' };

const sevBars = [1,2,3,4,5].map(i => {
  const filled = i <= classifierNode.severity;
  const color = classifierNode.severity >= 4 ? '#ef4444' : classifierNode.severity === 3 ? '#f97316' : '#eab308';
  return `<td style="width:20px;height:10px;background:${filled ? color : '#e5e7eb'};border-radius:3px;margin-right:2px"></td>`;
}).join('');

return [
  {
    json: {
      product: classifierNode.product,
      severity: classifierNode.severity,
      severity_bars: sevBars,
      complaint_id: $('Complaint Intake Form').first().json['Complaint ID'] || `AUTO-${Date.now()}`,
      customer_email: $('Complaint Intake Form').first().json['Customer Email'] || '',
      original_complaint: $('Complaint Intake Form').first().json['Complaint Narrative'] || '',
      risk_level: risk,
      risk_color: riskColors[risk] || riskColors.LOW,
      risk_bg: riskBg[risk] || riskBg.LOW,
      assigned_team: (router.assigned_team || '').replace(/_/g, ' '),
      priority: router.priority,
      priority_color: priorityColors[router.priority] || '#6b7280',
      sla_hours: router.sla_hours,
      routing_reasoning: router.routing_reasoning || '',
      sentiment: sentiment.overall_sentiment || 'N/A',
      urgency: sentiment.urgency_level || 'N/A',
      is_vulnerable: sentiment.is_vulnerable_consumer || false,
      resolution_summary: $json.resolution_summary || '',
      subject_line: $json.customer_response?.subject_line || '',
      customer_body: $json.customer_response?.body || '',
      escalation_needed: $json.escalation_needed ?? false,
      remediation_steps_html: ($json.remediation_steps || []).map((s, i) => `<tr><td style="padding:8px 12px;border-bottom:1px solid #f3f4f6;color:#6366f1;font-weight:700;width:30px">${s.step}</td><td style="padding:8px 12px;border-bottom:1px solid #f3f4f6;color:#111827">${s.action}</td><td style="padding:8px 12px;border-bottom:1px solid #f3f4f6;color:#6b7280;font-size:12px">${(s.responsible_team || '').replace(/_/g,' ')}</td><td style="padding:8px 12px;border-bottom:1px solid #f3f4f6;color:#6b7280;font-size:12px">${s.deadline_days}d</td></tr>`).join(''),
      timestamp: new Date().toLocaleString('en-US', { dateStyle: 'medium', timeStyle: 'short' })
    }
  }
];

const parsed = JSON.parse($json.output);
const classifierNode = JSON.parse($('Complaint Category Classifier').first().json.output);
const compliance = JSON.parse($('Regulatory Compliance Checker').first().json.output);

return [
  {
    json: {
      complaint_id: $('Complaint Intake Form').first().json['Complaint ID'] || `AUTO-${Date.now()}`,
      customer_email: $('Complaint Intake Form').first().json['Customer Email'] || '',
      complaint_narrative: $('Complaint Intake Form').first().json['Complaint Narrative'] || '',
      requires_human_review: parsed.escalation_needed ?? false,
      resolution_summary: parsed.resolution_summary || '',
      subject_line: parsed.customer_response?.subject_line || '',
      customer_response_body: parsed.customer_response?.body || '',
      follow_up_required: parsed.follow_up_required ?? false,
      follow_up_days: parsed.follow_up_days ?? '',
      product: classifierNode.product || '',
      severity: classifierNode.severity || 0,
      risk_level: compliance.risk_level || 'LOW',
      output: JSON.stringify(parsed)
    }
  }
];

const parsed = JSON.parse($json.fields.output);
const classifierNode = JSON.parse($('Complaint Category Classifier').first().json.output);
const complaintId = $('Complaint Intake Form').first().json['Complaint ID'] || `AUTO-${Date.now()}`;

const followUp = parsed.follow_up_required
  ? `<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:14px 18px;margin-top:16px"><div style="font-size:11px;text-transform:uppercase;letter-spacing:1px;color:#166534;font-weight:600;margin-bottom:4px">Follow-Up Scheduled</div><div style="font-size:13px;color:#15803d">Our team will follow up with you within ${parsed.follow_up_days || 7} business days to ensure your issue has been fully resolved.</div></div>`
  : '';

return [
  {
    json: {
      customer_email: $('Complaint Intake Form').first().json['Customer Email'] || '',
      subject_line: parsed.customer_response?.subject_line || 'Update on Your Recent Complaint',
      body_html: `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:0;background:#f9fafb;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif"><div style="max-width:600px;margin:0 auto;padding:24px"><div style="background:linear-gradient(135deg,#1e3a5f,#1e40af);border-radius:12px 12px 0 0;padding:28px 32px;text-align:center"><div style="font-size:20px;font-weight:700;color:white">Customer Resolution Center</div><div style="font-size:12px;color:#93c5fd;margin-top:4px">Case Reference: ${complaintId}</div></div><div style="background:white;border:1px solid #e5e7eb;border-top:none;border-radius:0 0 12px 12px;padding:32px"><div style="font-size:15px;line-height:1.8;color:#1e293b;white-space:pre-wrap">${parsed.customer_response?.body || ''}</div>${followUp}<div style="margin-top:24px;padding-top:20px;border-top:1px solid #f3f4f6;text-align:center"><div style="font-size:12px;color:#9ca3af">If you have additional questions, reply to this email or call us at 1-800-XXX-XXXX.</div><div style="font-size:11px;color:#d1d5db;margin-top:8px">Case ${complaintId} &middot; This is an automated communication from our Customer Resolution Center</div></div></div></div></body></html>`,
      escalation_needed: parsed.escalation_needed ?? false
    }
  }
];
